pub fn create_hs256_verifier(secret: &[u8]) -> JwtVerifier {
    JwtVerifier::new()
        .with_secret(Algorithm::HS256, secret.to_vec())
        .with_allowed_algorithms(vec![Algorithm::HS256])
}

pub fn create_rs256_verifier(public_key_pem: &[u8]) -> JwtVerifier {
    JwtVerifier::new()
        .with_secret(Algorithm::RS256, public_key_pem.to_vec())
        .with_allowed_algorithms(vec![Algorithm::RS256])
}

pub fn create_multi_algorithm_verifier(
    secrets: HashMap<Algorithm, Vec<u8>>,
) -> JwtVerifier {
    let algorithms: Vec<Algorithm> = secrets.keys().copied().collect();
    let mut verifier = JwtVerifier::new().with_allowed_algorithms(algorithms);
    
    for (alg, secret) in secrets {
        verifier = verifier.with_secret(alg, secret);
    }
    
    verifier
}